Rule.Source:
  import sailpoint.object.Attributes;
  import sailpoint.object.Application;
  import sailpoint.object.Link;
  import sailpoint.object.ResourceObject;
  import sailpoint.connector.ConnectorFactory;
  import sailpoint.tools.Util;

  private boolean excludedResourceObject(Application application, ResourceObject resourceObject) {

    /*
        Handles ResourceObject analysis to determine if it should be excluded from Azure license reconciliation
    */

    import sailpoint.object.Attributes;
    import sailpoint.object.Application;
    import sailpoint.object.ResourceObject;
    import sailpoint.tools.Util;

    boolean exclude = false;

    if (Util.nullSafeCaseInsensitiveEq(application.getName(), "AD-AID")) {

      List accountNameHistory = resourceObject.getAttribute("accountNameHistory");

      if (accountNameHistory != null) {

        for (String currentValue : accountNameHistory) {

          if (!currentValue.matches("AMITA\\\\.*")) {

            exclude = true;

          }

        }

      }

    }

    return exclude;

  }

  private ResourceObject getResourceObject(Application application, Link link) {

    /*
        Leverages AD connector to obtain a ResourceObject representation of enabled/disabled account links.
        This is done to mitigate the chance of reconciliation being missed due to aggregation timing (i.e. outdated data on the account link).
    */

    import sailpoint.object.Application;
    import sailpoint.object.Link;
    import sailpoint.object.ResourceObject;
    import sailpoint.tools.Util;

    ResourceObject resourceObject = null;

    Object appConnector = sailpoint.connector.ConnectorFactory.getConnector(application, null);

    if (appConnector != null) {

      String objectType = "account";
      Map optionsMap = new HashMap();

      if (link.getNativeIdentity() != null) {

        resourceObject = appConnector.getObject(objectType, link.getNativeIdentity(), optionsMap);

      }

    }

    return resourceObject;

  }

  private String reconcileAzureLicenseOnDisable(Application application, Link link) {

    /*
        Reconciles Azure license during DISABLE operations
    */

    import sailpoint.object.Attributes;
    import sailpoint.object.Application;
    import sailpoint.object.Link;
    import sailpoint.object.ResourceObject;
    import sailpoint.connector.ConnectorFactory;
    import sailpoint.tools.Util;

    String output = null;
    String ea6 = "extensionAttribute6";

    ResourceObject resourceObject = getResourceObject(application, link);

    if (resourceObject != null) {

      boolean exclude = excludedResourceObject(application, resourceObject);

      if (!exclude) {

        String ea6Value = resourceObject.getAttribute(ea6);

        if (Util.nullSafeCaseInsensitiveEq(ea6Value, "365_Web") || Util.nullSafeCaseInsensitiveEq(ea6Value, "365_NoWeb")) {

          output = "GAL_Sync";

        }

      }

    }

    return output;

  }


  private String reconcileAzureLicenseOnEnable(Application application, Link link) {

    /*
        Reconciles Azure license during ENABLE operations
    */

    import sailpoint.object.Attributes;
    import sailpoint.object.Application;
    import sailpoint.object.Link;
    import sailpoint.object.ResourceObject;
    import sailpoint.connector.ConnectorFactory;
    import sailpoint.tools.Util;

    String output = null;
    String msExCA5 = "msExchExtensionCustomAttribute5";
    String ea6 = "extensionAttribute6";

    ResourceObject resourceObject = getResourceObject(application, link);

    if (resourceObject != null) {

      boolean exclude = excludedResourceObject(application, resourceObject);

      if (!exclude) {

        String msExCA5Value = resourceObject.getAttribute(msExCA5);
        String ea6Value = resourceObject.getAttribute(ea6);

        if (!Util.nullSafeEq(msExCA5Value, "Resource") && Util.nullSafeCaseInsensitiveEq(ea6Value, "GAL_Sync")) {

          output = "365_NoWeb";

        }

      }

    }

    return output;

  }
